    "imageonly":true,
    "defination" :[
      {
        "title":"",
        "phase": '<p><strong>Diagnosis: Philadelphia chromosome–positive B-cell ALL</strong> is characterized by the (9;22) translocation which produces the <strong><em>BCR-ABL1</em> fusion</strong> resulting in a constitutively active ABL1 kinase.</p><p><strong>Treatment recommendation: </strong>An<strong> ABL1 tyrosine kinase inhibitor (TKI)</strong>, such as imatinib or dasatinib, should be component of initial induction chemotherapy regardless of intensity of chemotherapy.</p><div class="suggested_readings"><p>Suggested Readings:</p><p>Greer JP, Arber DA, Glader BE, List AF, Means RT Jr, Rodgers GM. <em>Wintrobe&apos;s Clinical Hematology</em>. 14th ed. Wolters Kluwer; 2018.</p><p>Kaushansky K, Prchal JT, Burns LJ, Lichtman MA, Levi M, Linch DC. <em>Williams Hematology</em>. 10th ed. McGraw Hill; 2021.</p></div>'
      }
    ]
