    "imgalt":"",
    "imageonly":true,
    "defination" :[
      {
        "title":"",
        "phase": '<p>Phase <span class="aria_label" role="text" aria-label="Roman Number Three"><span aria-hidden="true">III</span></span> randomized studies show that for CD19+, CD22+ B-cell ALL, the novel agents <strong>blinatumomab (TOWER study)</strong> and <strong>inotuzumab ozogamicin (INO-VATE study)</strong> salvage more patients with relapsed B-cell ALL then cytotoxic chemotherapy.</p><p>Blinatumomab is a CD19-CD3 bispecific T-cell engager.</p><p>Inotuzumab is an anti-CD22 antibody-chemotherapy drug conjugate.</p><div class="suggested_readings"><p>Suggested Readings:</p><p>Kantarjian, et al. <em>N Eng J Med</em>. 2017;376:836<span class="aria_label" role="text" aria-label="To"><span aria-hidden="true">-</span></span>847.</p><p>Kantarjian, et al. <em>N Eng J Med</em>. 2016;375:740<span class="aria_label" role="text" aria-label="To"><span aria-hidden="true">-</span></span>753.</p><p>Greer JP, Arber DA, Glader BE, List AF, Means RT Jr, Rodgers GM. <em>Wintrobe&apos;s Clinical Hematology</em>. 14th ed. Wolters Kluwer; 2018.</p><p>Kaushansky K, Prchal JT, Burns LJ, Lichtman MA, Levi M, Linch DC. <em>Williams Hematology</em>. 10th ed. McGraw Hill; 2021.</p></div>'
      }
    ]
