    "card_no": '94',
    "term":'<p><strong>A 62-year-old man with a history of multiple myeloma presents to the ER with severe back pain and new-onset weakness of the lower extremities along with urinary retention.</strong></p><div class="box-green-border"><strong>Which radiographic test should be performed immediately?</strong></div>',
    "termaudio":"",
